SELECT fee_type, SUM(amount) AS total_amount
FROM fee_details
GROUP BY fee_type;

SELECT class_name, COUNT(*) AS class_count
FROM class_types
GROUP BY class_name;

SELECT sub_class_name, sub_class_description
FROM sub_classes
WHERE class_id = 1;

SELECT COUNT(*) AS active_fee_schedules_count
FROM fee_schedules
WHERE active = 1;
